106: // PostStartHook returns the hook func that launches the config provider
107: func (p RESTStorageProvider) PostStartHook() (string, genericapiserver.PostStartHookFunc, error) {
108: 	bce := &bootstrapConfigurationEnsurer{
109: 		informersSynced: []cache.InformerSynced{
110: 			p.InformerFactory.Flowcontrol().V1().PriorityLevelConfigurations().Informer().HasSynced,
111: 			p.InformerFactory.Flowcontrol().V1().FlowSchemas().Informer().HasSynced,
112: 		},
113: 		fsLister:  p.InformerFactory.Flowcontrol().V1().FlowSchemas().Lister(),
114: 		plcLister: p.InformerFactory.Flowcontrol().V1().PriorityLevelConfigurations().Lister(),
115: 	}
116: 	return PostStartHookName, bce.ensureAPFBootstrapConfiguration, nil
117: }
118: 
119: type bootstrapConfigurationEnsurer struct {
120: 	informersSynced []cache.InformerSynced
121: 	fsLister        flowcontrollisters.FlowSchemaLister
122: 	plcLister       flowcontrollisters.PriorityLevelConfigurationLister
123: }
124: 
125: func (bce *bootstrapConfigurationEnsurer) ensureAPFBootstrapConfiguration(hookContext genericapiserver.PostStartHookContext) error {
126: 	clientset, err := flowcontrolclient.NewForConfig(hookContext.LoopbackClientConfig)
127: 	if err != nil {
128: 		return fmt.Errorf("failed to initialize clientset for APF - %w", err)
129: 	}
130: 
131: 	err = func() error {
132: 		// get a derived context that gets cancelled after 5m or
133: 		// when the StopCh gets closed, whichever happens first.
134: 		ctx, cancel := contextFromChannelAndMaxWaitDuration(hookContext.Done(), 5*time.Minute)
135: 		defer cancel()
136: 
137: 		if !cache.WaitForCacheSync(ctx.Done(), bce.informersSynced...) {
138: 			return fmt.Errorf("APF bootstrap ensurer timed out waiting for cache sync")
139: 		}
140: 
141: 		err = wait.PollImmediateUntilWithContext(
142: 			ctx,
143: 			time.Second,
144: 			func(context.Context) (bool, error) {
145: 				if err := ensure(ctx, clientset, bce.fsLister, bce.plcLister); err != nil {
146: 					klog.ErrorS(err, "APF bootstrap ensurer ran into error, will retry later")
147: 					return false, nil
148: 				}
149: 				return true, nil
150: 			})
151: 		if err != nil {
152: 			return fmt.Errorf("unable to initialize APF bootstrap configuration: %w", err)
153: 		}
154: 		return nil
155: 	}()
156: 	if err != nil {
157: 		return err
158: 	}
159: 
160: 	// we have successfully initialized the bootstrap configuration, now we
161: 	// spin up a goroutine which reconciles the bootstrap configuration periodically.
162: 	go func() {
163: 		wait.PollImmediateUntil(
164: 			time.Minute,
165: 			func() (bool, error) {
166: 				if err := ensure(hookContext, clientset, bce.fsLister, bce.plcLister); err != nil {
167: 					klog.ErrorS(err, "APF bootstrap ensurer ran into error, will retry later")
168: 				}
169: 				// always auto update both suggested and mandatory configuration
170: 				return false, nil
171: 			}, hookContext.Done())
172: 		klog.Info("APF bootstrap ensurer is exiting")
173: 	}()
174: 
175: 	return nil
176: }
177: 
178: func ensure(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
179: 
180: 	if err := ensureSuggestedConfiguration(ctx, clientset, fsLister, plcLister); err != nil {
181: 		// We should not attempt creation of mandatory objects if ensuring the suggested
182: 		// configuration resulted in an error.
183: 		// This only happens when the stop channel is closed.
184: 		return fmt.Errorf("failed ensuring suggested settings - %w", err)
185: 	}
186: 
187: 	if err := ensureMandatoryConfiguration(ctx, clientset, fsLister, plcLister); err != nil {
188: 		return fmt.Errorf("failed ensuring mandatory settings - %w", err)
189: 	}
190: 
191: 	if err := removeDanglingBootstrapConfiguration(ctx, clientset, fsLister, plcLister); err != nil {
192: 		return fmt.Errorf("failed to delete removed settings - %w", err)
193: 	}
194: 
195: 	return nil
196: }
197: 
198: func ensureSuggestedConfiguration(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
199: 	plcOps := ensurer.NewPriorityLevelConfigurationOps(clientset.PriorityLevelConfigurations(), plcLister)
200: 	if err := ensurer.EnsureConfigurations(ctx, plcOps, flowcontrolbootstrap.SuggestedPriorityLevelConfigurations, ensurer.NewSuggestedEnsureStrategy[*flowcontrolv1.PriorityLevelConfiguration]()); err != nil {
201: 		return err
202: 	}
203: 
204: 	fsOps := ensurer.NewFlowSchemaOps(clientset.FlowSchemas(), fsLister)
205: 	return ensurer.EnsureConfigurations(ctx, fsOps, flowcontrolbootstrap.SuggestedFlowSchemas, ensurer.NewSuggestedEnsureStrategy[*flowcontrolv1.FlowSchema]())
206: }
207: 
208: func ensureMandatoryConfiguration(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
209: 	plcOps := ensurer.NewPriorityLevelConfigurationOps(clientset.PriorityLevelConfigurations(), plcLister)
210: 	if err := ensurer.EnsureConfigurations(ctx, plcOps, flowcontrolbootstrap.MandatoryPriorityLevelConfigurations, ensurer.NewMandatoryEnsureStrategy[*flowcontrolv1.PriorityLevelConfiguration]()); err != nil {
211: 		return err
212: 	}
213: 
214: 	fsOps := ensurer.NewFlowSchemaOps(clientset.FlowSchemas(), fsLister)
215: 	return ensurer.EnsureConfigurations(ctx, fsOps, flowcontrolbootstrap.MandatoryFlowSchemas, ensurer.NewMandatoryEnsureStrategy[*flowcontrolv1.FlowSchema]())
216: }
217: 
218: func removeDanglingBootstrapConfiguration(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
219: 	if err := removeDanglingBootstrapFlowSchema(ctx, clientset, fsLister); err != nil {
220: 		return err
221: 	}
222: 
223: 	return removeDanglingBootstrapPriorityLevel(ctx, clientset, plcLister)
224: }
225: 
226: func removeDanglingBootstrapFlowSchema(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister) error {
227: 	bootstrap := append(flowcontrolbootstrap.MandatoryFlowSchemas, flowcontrolbootstrap.SuggestedFlowSchemas...)
228: 	fsOps := ensurer.NewFlowSchemaOps(clientset.FlowSchemas(), fsLister)
229: 	return ensurer.RemoveUnwantedObjects(ctx, fsOps, bootstrap)
230: }
231: 
232: func removeDanglingBootstrapPriorityLevel(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
233: 	bootstrap := append(flowcontrolbootstrap.MandatoryPriorityLevelConfigurations, flowcontrolbootstrap.SuggestedPriorityLevelConfigurations...)
234: 	plcOps := ensurer.NewPriorityLevelConfigurationOps(clientset.PriorityLevelConfigurations(), plcLister)
235: 	return ensurer.RemoveUnwantedObjects(ctx, plcOps, bootstrap)
236: }
